const input = $input.first();
const source = input && input.json ? input.json : {};

if (!source.stdout) {
  return [{
    json: {
      status: 20,
      payload: {},
      route_type: 'error',
      error_text: 'Parse CLI Result expected JSON input from Run CLI, but no stdout field was present. Execute the workflow from the trigger or run Run CLI first.',
    },
  }];
}

let envelope;
try {
  envelope = JSON.parse(source.stdout);
} catch (error) {
  return [{
    json: {
      status: 20,
      payload: {},
      route_type: 'error',
      error_text: `Parse CLI Result could not decode the Run CLI envelope: ${error.message}`,
    },
  }];
}

let payload;
try {
  payload = JSON.parse(envelope.stdout || '{}');
} catch (error) {
  return [{
    json: {
      status: Number(envelope.status || 20),
      payload: {},
      route_type: 'error',
      error_text: `Parse CLI Result could not decode the CLI payload JSON: ${error.message}`,
    },
  }];
}

const status = Number(envelope.status || 0);
const base = {
  status,
  payload,
};
if (status === 20 || payload.ok === false) {
  return [{
    json: {
      ...base,
      route_type: 'error',
      error_text: [
        'YouTube post repeater failed.',
        `Channel: ${payload.channel || 'unknown'}`,
        `Exit status: ${status}`,
        payload.error ? `Error: ${payload.error}` : 'Error: CLI returned a non-success status without an error message.',
      ].join('\n'),
    },
  }];
}
return [{
  json: {
    ...base,
    route_type: 'posts',
  },
}];

const payload = $json.payload || {};
const hasUsableImage = (url) => typeof url === 'string' && url.trim() !== '' && !url.includes('example.com');
const hasUsableMediaGroup = (media) => Array.isArray(media) && media.length > 0 && media.every((item) => hasUsableImage(item?.media));
return (payload.posts || []).map((post, index) => {
  let deliveryType = post.delivery_type;
  if (deliveryType === 'photo' && !hasUsableImage(post.images?.[0])) {
    deliveryType = 'message';
  }
  if (deliveryType === 'media_group' && !hasUsableMediaGroup(post.media)) {
    deliveryType = 'message';
  }
  return {
    json: {
      channel: payload.channel,
      fetched_at: payload.fetched_at,
      post_index: index,
      ...post,
      delivery_type: deliveryType,
    },
  };
});
